const hoy = new Date();
const hace7dias = new Date(hoy);
hace7dias.setDate(hace7dias.getDate() - 7);
const hace14dias = new Date(hoy);
hace14dias.setDate(hace14dias.getDate() - 14);

return [{
  json: {
    fecha_inicio: hace7dias.toISOString(),
    fecha_fin: hoy.toISOString(),
    fecha_inicio_anterior: hace14dias.toISOString(),
    fecha_fin_anterior: hace7dias.toISOString(),
    semana_label: `${hace7dias.toLocaleDateString('es-ES', {day:'2-digit',month:'short'})} – ${hoy.toLocaleDateString('es-ES', {day:'2-digit',month:'short', year:'numeric'})}`
  }
}];

const pedidosActuales = $node['Pedidos esta semana'].json.orders || [];
const pedidosAnteriores = $node['Pedidos semana anterior'].json.orders || [];
const productos = $node['Productos con stock bajo'].json.products || [];
const semana = $node['Calcular fechas de la semana'].json.semana_label;

// KPIs actuales
const ventasTotales = pedidosActuales.reduce((s, o) => s + parseFloat(o.total_price), 0);
const numPedidos = pedidosActuales.length;
const aov = numPedidos > 0 ? ventasTotales / numPedidos : 0;

// KPIs anteriores
const ventasAnteriores = pedidosAnteriores.reduce((s, o) => s + parseFloat(o.total_price), 0);
const pedidosAntNum = pedidosAnteriores.length;

// Variaciones
const varVentas = ventasAnteriores > 0 ? ((ventasTotales - ventasAnteriores) / ventasAnteriores * 100).toFixed(1) : 0;
const varPedidos = pedidosAntNum > 0 ? ((numPedidos - pedidosAntNum) / pedidosAntNum * 100).toFixed(1) : 0;

// Top productos
const conteoProductos = {};
for (const pedido of pedidosActuales) {
  for (const item of pedido.line_items) {
    conteoProductos[item.title] = (conteoProductos[item.title] || 0) + item.quantity;
  }
}
const topProductos = Object.entries(conteoProductos)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5);

// Stock crítico
const stockCritico = [];
for (const p of productos) {
  for (const v of p.variants) {
    if (v.inventory_quantity !== null && v.inventory_quantity <= 10) {
      stockCritico.push({
        nombre: p.title,
        variante: v.title !== 'Default Title' ? v.title : '',
        stock: v.inventory_quantity
      });
    }
  }
}

// Ventas por día (últimos 7)
const ventasPorDia = {};
for (let i = 6; i >= 0; i--) {
  const d = new Date();
  d.setDate(d.getDate() - i);
  ventasPorDia[d.toLocaleDateString('es-ES', {weekday:'short', day:'2-digit'})] = 0;
}
for (const pedido of pedidosActuales) {
  const dia = new Date(pedido.created_at).toLocaleDateString('es-ES', {weekday:'short', day:'2-digit'});
  if (ventasPorDia[dia] !== undefined) {
    ventasPorDia[dia] += parseFloat(pedido.total_price);
  }
}

return [{
  json: {
    semana, ventasTotales: ventasTotales.toFixed(2), numPedidos, aov: aov.toFixed(2),
    varVentas, varPedidos,
    ventasAnteriores: ventasAnteriores.toFixed(2), pedidosAntNum,
    topProductos, stockCritico,
    ventasPorDia
  }
}];
